
@main
struct UnicodeGenerator {
    static func main() {
        var result = """
        // This is an autogenerated file, do not edit directly.
        #if SWIFT_STDLIB_ENABLE_UNICODE_DATA

        import Swift\n\n
        """

        wordBreakData: do {
            let baseData = getWordBreakPropertyData(for: "utils/unicode/data/17/WordBreakProperty.txt")

            var idx = 0
            let data = baseData.map { (range, property) in
                idx += 1; return WordBreakEntry(index: idx, range: range, property: property)
            }

            let reorderedData = eytzingerize(data, dummy: .init(index: 0, range: 0...0, property: .extend))

            emit(wordBreakData: reorderedData, into: &result)
        }

        graphemeBreakData: do {
            let baseData = getGraphemeBreakPropertyData(for: "utils/unicode/data/17/GraphemeBreakProperty.txt")

            var data: [GraphemeBreakEntry] = []

            for (range, gbp) in baseData {
                guard range.count < 0x200 else {
                    let _ = String(range.lowerBound, radix: 16)
                    let _ = String(range.upperBound, radix: 16)

                    // Manual range
                    continue
                }

                data.append(.init(index: data.count, range: range, property: gbp))
            }

            let reorderedData = eytzingerize(data, dummy: .init(index: 0, range: 0...0, property: .control))

            emit(graphemeBreakData: reorderedData, into: &result)

            let derivedCoreProperties = readFile("utils/unicode/data/17/DerivedCoreProperties.txt")
            let consonants = getInCB(.consonant, from: derivedCoreProperties)
            emit(inCB: .consonant, consonants, into: &result)
        }

        scriptData: do {
            let scriptData = getScriptData(for: "utils/unicode/data/17/Scripts.txt")
            emit(scriptData: scriptData, into: &result)

            let scriptExtensionData = getScriptExtensionData(for: "utils/unicode/data/17/ScriptExtensions.txt")
            emit(scriptExtensionData: scriptExtensionData, into: &result)
        }

        emojiData: do {
            let emojiData = getEmojiData(for: "utils/unicode/data/17/emoji-data.txt")
            emit(emojiData: emojiData, into: &result)
        }

        caseData: do {
            let caseData = getCaseData(for: "utils/unicode/data/17/CaseFolding.txt")
            emit(caseData: caseData, into: &result)
        }

        normalizationData: do {
            let derivedNormalizationProps = readFile("utils/unicode/data/17/DerivedNormalizationProps.txt")

            let unicodeData = readFile("utils/unicode/data/17/UnicodeData.txt")

            var normData: [UInt32: UInt16] = [:]
            getQCData(from: derivedNormalizationProps, with: &normData)
            getCCCData(from: unicodeData, with: &normData)

            let flattenedNormData = flatten(Array(normData))
            emit(normData: flattenedNormData, into: &result)

            let decompData = getDecompData(from: unicodeData)
            let decompMph = Mph(for: decompData.map { UInt64($0.0) }) // TODO: Try key-path
            emit(decomp: decompMph, decompData, into: &result)

            let compExclusions = getCompExclusions(from: derivedNormalizationProps)
            let filteredDecomp = decompData.filter { (scalar, _) in
                !compExclusions.contains { $0.contains(scalar) }
            }
            // TODO: Interesting...
            let compMph = Mph(for: Array(Set(filteredDecomp.map { UInt64($0.1[1]) })))
            emit(comp: compMph, filteredDecomp, into: &result)
        }

        scalarData: do {

        }

        result += "#endif"

        print(result)
    }
}

extension Bool {
    var not: Self { !self }
}

extension Unicode {
    enum WordBreakProperty: UInt8 {
        case extend
        case format
        case katakana
        case hebrewLetter
        case aLetter
        case midNumLet
        case midLetter
        case midNum
        case numeric
        case extendNumLet
        case wSegSpace

        init?(_ string: borrowing String) {
            guard let value: Self = switch string {
                case "Extend":        .extend
                case "Format":        .format
                case "Katakana":      .katakana
                case "Hebrew_Letter": .hebrewLetter
                case "ALetter":       .aLetter
                case "MidNumLet":     .midNumLet
                case "MidLetter":     .midLetter
                case "MidNum":        .midNum
                case "Numeric":       .numeric
                case "ExtendNumLet":  .extendNumLet
                case "WSegSpace":     .wSegSpace
                case _: nil
            } else { return nil }
            self = value
        }
    }

    enum GraphemeBreakProperty: UInt32 {
        case control
        case extend
        case prepend
        case spacingMark

        init?(_ string: String) {
            guard let value: Self = switch string {
                case "Extend":              .extend
                case "Control", "CR", "LF": .control
                case "Prepend":             .prepend
                case "SpacingMark":         .spacingMark
                case _: nil
            } else {
                return nil
            }
            self = value
        }
    }

    enum IndicConjunctBreakProperty: String {
        case consonant = "Consonant"
        case extend = "Extend"
    }

