struct WordBreakEntry: Comparable {
    let index: Int
    let range: ClosedRange<UInt32>
    let property: Unicode.WordBreakProperty

    static func < (lhs: Self, rhs: Self) -> Bool { lhs.index < rhs.index }
}

struct GraphemeBreakEntry: Comparable {
    let index: Int
    let range: ClosedRange<UInt32>
    let property: Unicode.GraphemeBreakProperty

    static func < (lhs: Self, rhs: Self) -> Bool { lhs.index < rhs.index }
}

typealias WordBreakPropertyData     = [(range: ClosedRange<UInt32>, property: Unicode.WordBreakProperty)]
typealias GraphemeBreakPropertyData = [(range: ClosedRange<UInt32>, property: Unicode.GraphemeBreakProperty)]
typealias ScriptData                = [(range: ClosedRange<UInt32>, property: String)]
typealias ScriptExtensionData       = [(range: ClosedRange<UInt32>, property: [String])]
typealias EmojiData                 = [ClosedRange<UInt32>]
typealias CaseData                  = [UInt32: [UInt32]]
typealias DecompData                = [(UInt32, [UInt32])]
typealias CompExclusions            = [ClosedRange<UInt32>]

func getCaseData(for path: String) -> CaseData {
    let data = readFile(path)

    var mappings: CaseData = [:]

    for line in data.split(separator: "\n") {
        // Skip comments
        if line.hasPrefix("#") { continue }

        let components = line.split(separator: ";")

        let status = components[1].filter { !$0.isWhitespace }

        // We only care about Common and Full case mappings.
        guard status == "C" || status == "F" else {
            continue
        }

        let scalar = UInt32(components[0], radix: 16)!

        let mapping = components[2].split(separator: " ").map { UInt32($0, radix: 16)! }

        mappings[scalar] = mapping
    }

    return mappings
}

func getWordBreakPropertyData(for path: String) -> WordBreakPropertyData {
    let data = readFile(path)

    var unflattened: WordBreakPropertyData = []

    for line in data.split(separator: "\n") {
        if line.hasPrefix("#") { continue }

        let components = line.split(separator: ";")

        let splitProperty = components[1].split(separator: "#")
        let filteredProperty = splitProperty[0].filter(\.isWhitespace.not)

        guard let gbp = Unicode.WordBreakProperty(filteredProperty) else { continue }

        let filteredScalars = components[0].filter(\.isWhitespace.not)

        let scalars = if filteredScalars.contains(".") {
            let range = filteredScalars.split(separator: ".")
            then UInt32(range[0], radix: 16)! ... UInt32(range[1], radix: 16)!
        } else {
            let scalar = UInt32(filteredScalars, radix: 16)!
            then scalar...scalar
        }

        unflattened.append((scalars, gbp))
    }

    return flatten(unflattened)
}

