// Given a string to the UnicodeData file, return the flattened list of scalar
// to Canonical Decompositions.
//
// Each line in this data file is formatted like the following:
//
//     1B06;BALINESE LETTER AKARA TEDUNG;Lo;0;L;1B05 1B35;;;;N;;;;;
//
// Where each section is split by a ';'. The first section informs us of the
// scalar in the line with the various properties. For the purposes of
// decomposition data, we only need the 1B05 1B35 after the L (index 5) which is
// the array of scalars that the scalars decomposes to.
func getDecompData(from data: String) -> DecompData {
    var unflattened: DecompData = []

    for line in data.split(separator: "\n") {
        let components = line.split(separator: ";", omittingEmptySubsequences: false)

        let decomp = components[5]

        // We either 1. don't have decompositions, or 2. the decompositions is for
        // compatible forms. We only care about NFD, so ignore these cases.
        if decomp == "" || decomp.hasPrefix("<") {
            continue
        }

        let decomposedScalars = decomp.split(separator: " ").map {
            UInt32($0, radix: 16)!
        }

        let scalarStr = components[0]
        let scalar = UInt32(scalarStr, radix: 16)!

        unflattened.append((scalar, decomposedScalars))
    }

    return unflattened
}

func getCompExclusions(from data: String) -> CompExclusions {
    var result: CompExclusions = []

    for line in data.split(separator: "\n") {
        // Skip comments
        if line.hasPrefix("#") { continue }

        let info = line.split(separator: "#")
        let components = info[0].split(separator: ";")

        // Get the property first because we only care about Full_Composition_Exclusion
        let filteredProperty = components[1].filter { !$0.isWhitespace }

        guard filteredProperty == "Full_Composition_Exclusion" else { continue }

        let filteredScalars = components[0].filter { !$0.isWhitespace }

        // If we have . appear, it means we have a legitimate range. Otherwise,
        // it's a singular scalar.
        let scalars = if filteredScalars.contains(".") {
            let range = filteredScalars.split(separator: ".")
            then UInt32(range[0], radix: 16)! ... UInt32(range[1], radix: 16)!
        } else {
            let scalar = UInt32(filteredScalars, radix: 16)!
            then scalar...scalar
        }

        result.append(scalars)
    }

    return result
}

func emit(caseData data: CaseData, into result: inout String) {
    let caseMph = Mph(for: data.keys.map(UInt64.init))

    emitMph(
        caseMph,
        name: "Case",
        label: "CaseFold",
        into: &result
    )

    var caseData: [(UInt32, [UInt32])] = .init(
        repeating: (0, []),
        count: data.keys.count
    )

    for (key, mapping) in data {
        let idx = caseMph.index(for: UInt64(key))
        caseData[idx] = (key, mapping)
    }

    emitCollection(
        caseData,
        name: "unicodeCase",
        type: "UInt64",
        into: &result
    ) {
        // Our original scalar goes at the bottom 21 bits.
        var value = UInt64($0)

        // If our scalar is a Full mapping (maps to more than 1 scalar), then
        // set the top bit to indicate another look through and move on.
        guard $1.count == 1 else {
            value |= 0x1 << 63
            return "0x\(String(value, radix: 16, uppercase: true))"
        }

        let distance = Int32($0) - Int32($1[0])

        value |= UInt64(UInt32(bitPattern: distance)) << 21

        return "0x\(String(value, radix: 16, uppercase: true))"
    }

    let fullData = data.filter { $1.count > 1 }
    let fullMph = Mph(for: fullData.keys.map { UInt64($0) })

    emitMph(
        fullMph,
        name: "CaseFull",
        label: "CaseFullFold",
        into: &result
    )

    var fullCaseData: [(UInt32, [UInt32])] = .init(
        repeating: (0, []),
        count: fullData.count
    )

    for (key, mapping) in fullData {
        let idx = fullMph.index(for: UInt64(key))
        fullCaseData[idx] = (key, mapping)
    }

    emitCollection(
        fullCaseData,
        name: "unicodeCaseFull",
        type: "UInt64",
        into: &result
    ) {
        var value: UInt64 = 0

        // Store the count in the top 2 bits.
        precondition((2...3).contains($1.count))
        value |= UInt64($1.count) << 62

        for (i, scalar) in $1.enumerated() {
            let distance = Int32($0) - Int32(scalar)
            precondition(distance.magnitude <= UInt16.max)

            value |= UInt64(distance.magnitude) << (i * 17)

            if distance < 0 { value |= 0x10000 << (i * 17) }
        }

        return "0x\(String(value, radix: 16, uppercase: true))"
    }
}

func emit(wordBreakData data: [WordBreakEntry], into result: inout String) {
    emitCollection(
        data,
        name: "unicodeWords",
        type: "UInt32",
        into: &result
    ) {
        "0x\(String($0.range.lowerBound | (UInt32($0.range.count) << 21), radix: 16, uppercase: true))"
    }

    emitCollection(
        data,
        name: "unicodeWordsData",
        type: "UInt8",
        into: &result
    ) {
        "0x\(String($0.property.rawValue, radix: 16, uppercase: true))"
    }
}

func emit(graphemeBreakData data: [GraphemeBreakEntry], into result: inout String) {
    result += "let unicodeGraphemeBreakProperties: InlineArray<\(data.count), UInt32> = [\n"

    formatCollection(data, into: &result) { entry in
        let range = entry.range
        let gbp = entry.property

        // Our value uses the 21 bits to represent the scalar, 8 bits to represent
        // the range's count, and finally the last three bits to represent the
        // grapheme break property enum.

        // E.g. for the top 3 bits:
        // 000 = control
        // 001 = extend
        // 010 = prepend
        // 011 = spacingMark
        // 100 = not used (will never occur)
        // 101 = not used (will never occur)
        // 110 = not used (will never occur)
        // 111 = not used (will never occur)
        var value = range.lowerBound
        value |= UInt32(range.count - 1) << 21
        value |= gbp.rawValue << 29

        return "0x\(String(value, radix: 16, uppercase: true))"
    }

    result += "\n]\n\n"
}

func emit(inCB incb: Unicode.IndicConjunctBreakProperty, _ data: [ClosedRange<UInt32>], into result: inout String) {
    // 64 bit arrays * 8 bytes = .512 KB
    var bitArrays: [BitArray] = .init(repeating: .init(size: 64), count: 64)

    let chunkSize = 0x110000 / 64 / 64

    var chunks: [Int] = []

    for i in 0 ..< 64 * 64 {
        let lower = i * chunkSize
        let upper = lower + chunkSize - 1

        let idx = i / 64
        let bit = i % 64

        for scalar in lower ... upper {
            if data.contains(where: { $0.contains(UInt32(scalar)) }) {
                chunks.append(i)

                bitArrays[idx][bit] = true
                break
            }
        }
    }

    // Remove the trailing 0s. Currently this reduces quick look size down to
    // 96 bytes from 512 bytes.
    var reducedBA = Array(bitArrays.reversed())
    reducedBA = Array(reducedBA.drop { $0.words == [0x0] })

    bitArrays = reducedBA.reversed()

    // Keep a record of every rank for all the bitarrays.
    var ranks: [UInt16] = []

    // Record our quick look ranks.
    var lastRank: UInt16 = 0
    for (i, _) in bitArrays.enumerated() {
        guard i != 0 else {
            ranks.append(0)
            continue
        }

        var rank = UInt16(bitArrays[i - 1].words[0].nonzeroBitCount)
        rank += lastRank

        ranks.append(rank)

        lastRank = rank
    }

    // Insert our quick look size at the beginning.
    var size = BitArray(size: 64)
    size.words = [UInt64(bitArrays.count)]
    bitArrays.insert(size, at: 0)

    for chunk in chunks {
        var chunkBA = BitArray(size: chunkSize)

        let lower = chunk * chunkSize
        let upper = lower + chunkSize

        for scalar in lower ..< upper {
            if data.contains(where: { $0.contains(UInt32(scalar)) }) {
                chunkBA[scalar % chunkSize] = true
            }
        }

        // Append our chunk bit array's rank.
        var lastRank: UInt16 = 0
        for (i, _) in chunkBA.words.enumerated() {
            guard i != 0 else {
                ranks.append(0)
                continue
            }

            var rank = UInt16(chunkBA.words[i - 1].nonzeroBitCount)
            rank += lastRank

            ranks.append(rank)
            lastRank = rank
        }

        bitArrays += chunkBA.words.map {
            var ba = BitArray(size: 64)
            ba.words = [$0]
            return ba
        }
    }

    emitCollection(
        ranks,
        name: "unicodeInCB\(incb.rawValue)Ranks",
        into: &result
    )

    emitCollection(
        bitArrays,
        name: "unicodeInCB\(incb.rawValue)",
        type: "UInt64",
        into: &result
    ) {
        precondition($0.words.count == 1)
        return "0x\(String($0.words[0], radix: 16, uppercase: true))"
    }
}

func emit(scriptData data: ScriptData, into result: inout String) {
    var scriptData: [UInt32: Unicode.Script] = [:]

    for (range, property) in data {
        for scalar in range {
            scriptData[scalar] = Unicode.Script(rawValue: property)
        }
    }

    for i in 0x0...0x10FFFF {
        guard let scalar = Unicode.Scalar(i) else { continue }

        if !scriptData.keys.contains(scalar.value) {
            scriptData[scalar.value] = .unknown
        }
    }

    let data = flatten(Array(scriptData))

    emitCollection(
        data,
        name: "unicodeScripts",
        type: "UInt32",
        into: &result
    ) {
        var value = $0.0.lowerBound // TODO: This is unreadable.
        value |= UInt32(unsafeBitCast($0.1, to: UInt8.self)) << 21

        return "0x\(String(value, radix: 16, uppercase: true))"
    }
}

func emit(scriptExtensionData data: ScriptExtensionData, into result: inout String) {
    var indices: [[String]: UInt16] = [:]
    var bytes: [UInt8] = []
    var currentIndex: UInt16 = 0

    for (_, scripts) in data {
        if indices.keys.contains(scripts) { continue }

        indices[scripts] = currentIndex | (UInt16(scripts.count) << 11)

        for script in scripts {
            let scriptEnum = Unicode.Script(fromAbbreviation: script)!
            let byte = unsafeBitCast(scriptEnum, to: UInt8.self)

            bytes.append(byte)
            currentIndex += 1
        }
    }

    // 64 bit arrays * 8 bytes = .512 KB
    var bitArrays: [BitArray] = .init(repeating: .init(size: 64), count: 64)

    let chunkSize = 0x110000 / 64 / 64

    var chunks: [Int] = []

    for i in 0 ..< 64 * 64 {
        let lower = i * chunkSize
        let upper = lower + chunkSize - 1

        let idx = i / 64
        let bit = i % 64

        for scalar in lower ... upper {
            if data.contains(where: { $0.0.contains(UInt32(scalar)) }) {
                chunks.append(i)

                bitArrays[idx][bit] = true
                break
            }
        }
    }

    // Remove the trailing 0s. Currently this reduces quick look size down to
    // 96 bytes from 512 bytes.
    var reducedBA = Array(bitArrays.reversed())
    reducedBA = Array(reducedBA.drop {
        $0.words == [0x0]
    })

    bitArrays = reducedBA.reversed()

    // Keep a record of every rank for all the bitarrays.
    var ranks: [UInt16] = []

    // Record our quick look ranks.
    var lastRank: UInt16 = 0
    for (i, _) in bitArrays.enumerated() {
        guard i != 0 else {
            ranks.append(0)
            continue
        }

        var rank = UInt16(bitArrays[i - 1].words[0].nonzeroBitCount)
        rank += lastRank

        ranks.append(rank)

        lastRank = rank
    }

    // Insert our quick look size at the beginning.
    var size = BitArray(size: 64)
    size.words = [UInt64(bitArrays.count)]
    bitArrays.insert(size, at: 0)

    var dataIndices: [UInt16] = []

    for chunk in chunks {
        var chunkBA = BitArray(size: chunkSize)

        let lower = chunk * chunkSize
        let upper = lower + chunkSize

        let chunkDataIdx = UInt64(dataIndices.endIndex)

        // Insert our chunk's data index in the upper bits of the last word of our
        // bit array.
        chunkBA.words[chunkBA.words.endIndex - 1] |= chunkDataIdx << 16

        for scalar in lower ..< upper {
            if data.contains(where: { $0.0.contains(UInt32(scalar)) }) {
                chunkBA[scalar % chunkSize] = true

                let data = data[data.firstIndex {
                    $0.0.contains(UInt32(scalar))
                }!].1

                dataIndices.append(indices[data]!)
            }
        }

        // Append our chunk bit array's rank.
        var lastRank: UInt16 = 0
        for (i, _) in chunkBA.words.enumerated() {
            guard i != 0 else {
                ranks.append(0)
                continue
            }

            var rank = UInt16(chunkBA.words[i - 1].nonzeroBitCount)
            rank += lastRank

            ranks.append(rank)
            lastRank = rank
        }

        bitArrays += chunkBA.words.map {
            var ba = BitArray(size: 64)
            ba.words = [$0]
            return ba
        }
    }

    emitCollection(
        bytes,
        name: "unicodeScriptExtensionsData",
        into: &result
    )

    emitCollection(
        dataIndices,
        name: "unicodeScriptExtensionsDataIndices",
        into: &result
    )

    emitCollection(
        ranks,
        name: "unicodeScriptExtensionsRanks",
        into: &result
    )

    emitCollection(
        bitArrays,
        name: "unicodeScriptExtensions",
        type: "UInt64",
        into: &result
    ) {
        precondition($0.words.count == 1)
        return "0x\(String($0.words[0], radix: 16, uppercase: true))"
    }
}

