    }
}

func emit(normData data: [(ClosedRange<UInt32>, UInt16)], into result: inout String) {
    let uniqueData = Array(Set(data.map { $0.1 }))

    // 64 bit arrays * 8 bytes = .512 KB
    var bitArrays: [BitArray] = .init(repeating: .init(size: 64), count: 64)

    let chunkSize = 0x110000 / 64 / 64

    var chunks: [Int] = []

    for i in 0 ..< 64 * 64 {
        let lower = i * chunkSize
        let upper = lower + chunkSize - 1

        let idx = i / 64
        let bit = i % 64

        for scalar in lower...upper {
            if data.contains(where: { $0.0.contains(UInt32(scalar)) }) {
                chunks.append(i)

                bitArrays[idx][bit] = true
                break
            }
        }
    }

    // Remove the trailing 0s. Currently this reduces quick look size down to
    // 96 bytes from 512 bytes.
    var reducedBA = Array(bitArrays.reversed())
    reducedBA = Array(reducedBA.drop { $0.words == [0x0] })

    bitArrays = reducedBA.reversed()

    // Keep a record of every rank for all the bitarrays.
    var ranks: [UInt16] = []

    // Record our quick look ranks.
    var lastRank: UInt16 = 0
    for (i, _) in bitArrays.enumerated() {
        guard i != 0 else {
            ranks.append(0)
            continue
        }

        var rank = UInt16(bitArrays[i - 1].words[0].nonzeroBitCount)
        rank += lastRank

        ranks.append(rank)

        lastRank = rank
    }

    // Insert our quick look size at the beginning.
    var size = BitArray(size: 64)
    size.words = [UInt64(bitArrays.count)]
    bitArrays.insert(size, at: 0)

    var dataIndices: [UInt8] = []

    for chunk in chunks {
        var chunkBA = BitArray(size: chunkSize)

        let lower = chunk * chunkSize
        let upper = lower + chunkSize

        let chunkDataIdx = UInt64(dataIndices.endIndex)

        // Insert our chunk's data index in the upper bits of the last word of our
        // bit array.
        chunkBA.words[chunkBA.words.endIndex - 1] |= chunkDataIdx << 16

        for scalar in lower ..< upper where data.contains(where: { $0.0.contains(UInt32(scalar)) }) {
            chunkBA[scalar % chunkSize] = true

            let data = data[data.firstIndex { $0.0.contains(UInt32(scalar)) }!].1
            let dataIdx = uniqueData.firstIndex(of: data)!

            dataIndices.append(UInt8(dataIdx))
        }

        // Append our chunk bit array's rank.
        var lastRank: UInt16 = 0
        for (i, _) in chunkBA.words.enumerated() {
            guard i != 0 else {
                ranks.append(0)
                continue
            }

            var rank = UInt16(chunkBA.words[i - 1].nonzeroBitCount)
            rank += lastRank

            ranks.append(rank)
            lastRank = rank
        }

        bitArrays += chunkBA.words.map {
            var ba = BitArray(size: 64)
            ba.words = [$0]
            return ba
        }
    }

    emitCollection(
        uniqueData,
        name: "unicodeNormDataData",
        into: &result
    )

    emitCollection(
        dataIndices,
        name: "unicodeNormDataDataIndices",
        into: &result
    )

    emitCollection(
        ranks,
        name: "unicodeNormDataRanks",
        into: &result
    )

    emitCollection(
        bitArrays,
        name: "unicodeNormData",
        type: "UInt64",
        into: &result
    ) {
        precondition($0.words.count == 1)
        return "0x\(String($0.words[0], radix: 16, uppercase: true))"
    }
}

// Takes a mph for the keys and the data values and writes the required data into arrays.
func emit(decomp mph: Mph, _ data: [(UInt32, [UInt32])], into result: inout String) {
    emitMph(
        mph,
        name: "NfdDecomp",
        label: "NfdDecomp",
        into: &result
    )

    // Fixup the decomposed scalars first for full decompositions.

    var data = data

    func decompose(_ scalar: UInt32, into result: inout [UInt32]) {
        if scalar <= 0x7F {
            result.append(scalar)
            return
        }

        if let decomp = data.first(where: { $0.0 == scalar }) {
            for scalar in decomp.1 {
                decompose(scalar, into: &result)
            }
        } else {
            result.append(scalar)
        }
    }

    for (i, (_, rawDecomposed)) in data.enumerated() {
        var newDecomposed: [UInt32] = []

        for rawScalar in rawDecomposed {
            decompose(rawScalar, into: &newDecomposed)
        }

        data[i].1 = newDecomposed
    }

    var sortedData: [(UInt32, UInt16)] = []

    for (scalar, _) in data {
        sortedData.append((scalar, UInt16(mph.index(for: UInt64(scalar)))))
    }

    sortedData.sort { $0.1 < $1.1 }

    let indices = emit(decompDecomp: data, sortedData, into: &result)
    emit(decompIndices: indices, into: &result)
}

func emit(
    decompDecomp data: [(UInt32, [UInt32])],
    _ sortedData: [(UInt32, UInt16)],
    into result: inout String
) -> [(UInt32, UInt16)] {
    var indices: [(UInt32, UInt16)] = []
    var decompResult: [UInt8] = []

    // Keep a record of decompositions because some scalars share the same
    // decomposition, so instead of emitting it twice, both scalars just point at
    // the same decomposition index.
    var uniqueDecomps: [[UInt32]: UInt16] = [:]

    for (scalar, _) in sortedData {
        let decomp = data.first(where: { $0.0 == scalar })!.1

        // If we've seen this decomp before, use it.
        if let idx = uniqueDecomps[decomp] {
        indices.append((scalar, idx))
        continue
        }

        indices.append((scalar, UInt16(decompResult.count)))

        // This is our NFD decomposition utf8 string count.
        decompResult.append(0)
        let sizeIdx = decompResult.count - 1

        uniqueDecomps[decomp] = UInt16(sizeIdx)

        for scalar in decomp {
            let realScalar = Unicode.Scalar(scalar)!
            decompResult[sizeIdx] += UInt8(realScalar.utf8.count)
            for utf8 in realScalar.utf8 { decompResult.append(utf8) }
        }
    }

    result += "let unicodeNfdDecomp: InlineArray<\(decompResult.count), UInt8> = [\n"

    formatCollection(decompResult, into: &result) { value -> String in
        return "0x\(String(value, radix: 16, uppercase: true))"
    }

    result += "\n]\n\n"

    return indices
}

func emit(decompIndices indices: [(UInt32, UInt16)], into result: inout String) {
    result += "let unicodeNfdDecompIndices: InlineArray<\(indices.count), UInt32> = [\n"

    formatCollection(indices, into: &result) { (scalar, idx) -> String in
        // Make sure that these scalars don't exceed past 18 bits. We need the other
        // 14 bits to store the index into decomp array. Although Unicode scalars
        // can go up to 21 bits, none of the higher scalars actually decompose into
        // anything or aren't assigned yet.
        precondition(scalar <= 0x3FFFF)
        var value = scalar
        value |= UInt32(idx) << 18

        return "0x\(String(value, radix: 16, uppercase: true))"
    }

    result += "\n]\n\n"
}

func emit(comp mph: Mph, _ data: [(UInt32, [UInt32])], into result: inout String) {
    emitMph(
        mph,
        name: "NfcComp",
        label: "NfcComp",
        into: &result
    )

    emit(compComps: mph, data, into: &result)
}

func emit(compComps mph: Mph, _ data: [(UInt32, [UInt32])], into result: inout String) {
    let uniqueKeys = Set(data.map { $0.1[1] })
    var sortedData: [[(UInt32, UInt32)]] = .init(
        repeating: [],
        count: uniqueKeys.count
    )

    for (scalar, comp) in data {
        let idx = mph.index(for: UInt64(comp[1]))
        if sortedData[idx].isEmpty { sortedData[idx].append((comp[1], .max)) }
        sortedData[idx].append((comp[0], scalar))
    }

    // Initialize our flat data and offsets arrays
    var flattenedCompValues: [String] = []
    var compOffsets: [UInt16] = [0]

    for compList in sortedData {
        // Collect the formatted hex strings for this specific composition list
        var formattedList: [String] = []

        for (comp, scalar) in compList {
            let hexString = if scalar == .max {
                // This only occurs for the first element who stores the original y scalar
                // in the composition and the size of the array.
                "0x\(String(comp, radix: 16, uppercase: true))"
            } else {
                // Make sure that these scalars don't exceed past 17 bits. We need the other
                // 15 bits to store the range to the final composition. Although Unicode
                // scalars can go up to 21 bits, none of the compositions with this scalar
                // go that high.
                precondition(comp <= 0x1FFFF)
                var value = comp

                // Calculate the distance from our current composition scalar to our final
                // composed scalar.
                let distance = Int(scalar) - Int(comp)
                // Make sure that our distance doesn't exceed 14 bits. Although the above
                // assertion gives us 15 bits, we use the last bit to indicate negative
                // or not.
                precondition(distance <= 0x3FFF)

                value |= UInt32(distance.magnitude) << 17

                if distance < 0 { value |= 1 << 31 }

                then "0x\(String(value, radix: 16, uppercase: true))"
            }

            formattedList.append(hexString)
        }

        flattenedCompValues.append(contentsOf: formattedList)
        compOffsets.append(UInt16(flattenedCompValues.count))
    }

    emitCollection(
        flattenedCompValues,
        name: "unicodeNfcCompData",
        type: "UInt32",
        into: &result,
        formatter: \.self
    )

    emitCollection(
        compOffsets,
        name: "unicodeNfcCompDataOffsets",
        into: &result
    )
}
